18	const COMPONENT_BASE_PREMIUM = 25;
19	
20	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: COMPONENT_BASE_PREMIUM,
26	  moonstone: COMPONENT_BASE_PREMIUM,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
31	const PROCESSING_FEE = 5;
32	
33	const CURSED_SURCHARGE_RATE = 0.5;
34	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	
37	function isCursed(item: Item): boolean {
38	  return item.cursed === true;
39	}
40	
41	function isHighlyEnchanted(item: Item): boolean {
42	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
43	}
44	
45	function riskMultiplierForItem(item: Item): number {
46	  return (
47	    1 +
48	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
49	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
50	  );
51	}
52	
53	function basePremiumForItem(item: Item): number {
54	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
55	}
56	
57	type QuoteResult = { kind: "quote"; premium: number };
58	
59	const BUILDING_BLOCK_BASE_PREMIUM = 60;
60	const BUILDING_BLOCK_SIZE = 3;
61	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
62	
63	type ItemGroup = { kind: Item["kind"]; items: Item[] };
64	
65	function groupByKind(items: Item[]): ItemGroup[] {
66	  const groups = new Map<Item["kind"], Item[]>();
67	  for (const item of items) {
68	    const group = groups.get(item.kind) ?? [];
69	    group.push(item);
70	    groups.set(item.kind, group);
71	  }
72	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
73	}
74	
75	function isBuildingBlock(group: ItemGroup): boolean {
76	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
77	}
78	
79	function basePremiumForGroup(group: ItemGroup): number {
80	  if (isBuildingBlock(group)) {
81	    return BUILDING_BLOCK_BASE_PREMIUM;
82	  }
83	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
84	}
85	
86	function basePremiumForItems(items: Item[]): number {
87	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
88	}
89	
90	function quoteStep(step: QuoteStep, contractIndex: number): QuoteResult {
91	  const basePremium = basePremiumForItems(step.items);
92	  const customerRate =
93	    contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
94	  const adjustment = basePremium * customerRate;
95	  const premium = Math.ceil(basePremium + adjustment + PROCESSING_FEE);
96	  return { kind: "quote", premium };
97	}
98	
99	export function processScenario(scenario: Scenario): ScenarioResult {
100	  const results = scenario.steps.map((step, index) => quoteStep(step, index));
101	  return { results };
102	}
